def get_icon(name: str, color: str = "#cccccc", size: int = 20) -> QIcon:
    svg_template = _ICONS.get(name)
    if not svg_template:
        return QIcon()
    svg = svg_template.replace("currentColor", color)
    renderer = QSvgRenderer(QByteArray(svg.encode("utf-8")))
    pixmap = QPixmap(size, size)
    pixmap.fill(Qt.transparent)
    painter = QPainter(pixmap)
    renderer.render(painter)
    painter.end()
    return QIcon(pixmap)


def get_pixmap(name: str, color: str = "#cccccc", size: int = 20) -> QPixmap:
    icon = get_icon(name, color, size)
    return icon.pixmap(size, size)
